// Login handler
app.post('/login', async (req, res) => {
  const { username, password, rememberMe } = req.body;

  // Validate user
  const user = users[username];
  if (!user) {
    return res.status(401).send('Invalid username or password');
  }

  const passwordValid = await bcrypt.compare(password, user.passwordHash);
  if (!passwordValid) {
    return res.status(401).send('Invalid username or password');
  }

  // Login successful
  console.log(`[Login] User "${username}" logged in successfully`);

  // Handle "Remember Me"
  if (rememberMe === 'true') {
    const token = createRememberMeToken(username);

    // Set secure, httpOnly cookie with selector:validator
    res.cookie('remember_me', `${token.selector}:${token.validator}`, {
      httpOnly: true,       // Not accessible via JavaScript (XSS protection)
      secure: process.env.NODE_ENV === 'production', // HTTPS only in production
      sameSite: 'lax',      // CSRF protection
      maxAge: 30 * 24 * 60 * 60 * 1000, // 30 days
      path: '/'
    });

    console.log(`[Login] Remember Me token created for "${username}"`);
  }

  // Set a session cookie (short-lived, for current browser session)
  res.cookie('session_user', username, {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'lax',
    maxAge: 24 * 60 * 60 * 1000 // 1 day session
  });

  res.redirect('/dashboard');
});

